    self, func: Callable, args: tuple | None = None, kwargs: dict[str, object] | None = None
) -&gt; bool:
    r"""Return whether *func* is allowed to run while ``torch.compile`` is tracing."""
    if not bool(self._compile_safe.get(func, False)):
